//! Session Manager — persists domain events to JSONL, handles session lifecycle.
//!
//! Architecture:
//!   - Subscribes to domain events from the event bus
//!   - Appends events to JSONL file on each domain event
//!   - Supports session load/replay/list/delete
//!   - Periodic snapshots as load accelerators

use crate::event_bus::{ActorId, BusEventEnvelope, DomainEvent, EventBus};
use crate::session_jsonl::{self, JsonlReader, JsonlWriter, SessionMeta};
use std::collections::VecDeque;
use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

// ---------------------------------------------------------------------------
// Session Manager State
// ---------------------------------------------------------------------------

/// Session manager state — mutable only within the actor loop
#[derive(Debug)]
pub struct SessionState {
    /// Current session name (if any)
    pub session_name: Option<String>,
    /// Current JSONL writer (None if no active session)
    writer: Option<JsonlWriter>,
    /// Pending events to replay on load
    pending_events: VecDeque<DomainEvent>,
    /// Last snapshot timestamp (for periodic snapshots)
    last_snapshot: Option<Instant>,
    /// Whether session is dirty (has unsaved changes)
    is_dirty: bool,
}

impl Default for SessionState {
    fn default() -> Self {
        Self {
            session_name: None,
            writer: None,
            pending_events: VecDeque::new(),
            last_snapshot: None,
            is_dirty: false,
        }
    }
}

impl SessionState {
    /// Start a new session
    pub fn start_session(&mut self, name: String, provider: String, model: String) -> anyhow::Result<()> {
        // Close existing session if any
        self.close_session()?;

        let meta = SessionMeta::new(name.clone(), provider, model);
        let path = session_jsonl::session_path(&name)
            .ok_or_else(|| anyhow::anyhow!("No sessions directory"))?;

        // Ensure directory exists
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }

        self.writer = Some(JsonlWriter::create(&path, &meta)?);
        self.session_name = Some(name);
        self.pending_events.clear();
        self.last_snapshot = Some(Instant::now());
        self.is_dirty = true;
        Ok(())
    }

    /// Resume an existing session (append mode)
    pub fn resume_session(&mut self, name: String) -> anyhow::Result<SessionMeta> {
        // Close existing session if any
        self.close_session()?;

        let path = session_jsonl::session_path(&name)
            .ok_or_else(|| anyhow::anyhow!("No sessions directory"))?;

        self.writer = Some(JsonlWriter::append(&path)?);
        self.session_name = Some(name.clone());
        self.is_dirty = true;

        // Load and return metadata
        let mut reader = JsonlReader::open(&path)?;
        let meta = reader.read_meta()?;
        Ok(meta)
    }

    /// Close current session
    pub fn close_session(&mut self) -> anyhow::Result<()> {
        if let Some(mut writer) = self.writer.take() {
            writer.flush()?;
        }
        self.session_name = None;
        self.is_dirty = false;
        Ok(())
    }

    /// Record a domain event (append to JSONL)
    pub fn record_event(&mut self, event: &DomainEvent) -> anyhow::Result<()> {
        if let Some(ref mut writer) = self.writer {
            writer.write_event(event)?;
            self.is_dirty = true;
        }
        self.pending_events.push_back(event.clone());
        Ok(())
    }

    /// Check if snapshot is needed
    pub fn needs_snapshot(&self, interval: Duration) -> bool {
        self.last_snapshot.map(|t| t.elapsed() >= interval).unwrap_or(true)
    }

    /// Mark snapshot taken
    pub fn mark_snapshot(&mut self) {
        self.last_snapshot = Some(Instant::now());
    }

    /// Get pending events for replay
    pub fn take_pending_events(&mut self) -> Vec<DomainEvent> {
        self.pending_events.drain(..).collect()
    }

    /// Check if session is active
    pub fn has_active_session(&self) -> bool {
        self.session_name.is_some()
    }

    /// Check if session is dirty
    pub fn is_dirty(&self) -> bool {
        self.is_dirty
    }

    /// Flush pending writes
    pub fn flush(&mut self) -> anyhow::Result<()> {
        if let Some(ref mut writer) = self.writer {
            writer.flush()?;
            self.is_dirty = false;
        }
        Ok(())
    }
}

// ---------------------------------------------------------------------------
// Session Commands (for actor communication)
// ---------------------------------------------------------------------------

/// Commands sent to SessionManager actor
#[derive(Debug, Clone)]
pub enum SessionCmd {
    /// Start a new session
    StartSession { name: String, provider: String, model: String },
    /// Resume an existing session
    ResumeSession { name: String },
    /// Close current session
    CloseSession,
    /// Record a domain event
    RecordEvent { event: DomainEvent },
    /// Load a session (returns metadata + events)
    LoadSession { name: String },
    /// List all sessions
    ListSessions,
    /// Delete a session
    DeleteSession { name: String },
    /// Request periodic snapshot
    MaybeSnapshot,
    /// Flush pending writes
    Flush,
}

/// Response from SessionManager actor
#[derive(Debug, Clone)]
pub enum SessionResponse {
    /// Session started successfully
    SessionStarted { name: String },
    /// Session resumed successfully with metadata
    SessionResumed { meta: SessionMeta },
    /// Session closed
    SessionClosed,
    /// Event recorded
    EventRecorded,
    /// Session loaded with events
    SessionLoaded { meta: SessionMeta, events: Vec<DomainEvent> },
    /// List of session names
    SessionsListed { names: Vec<String> },
    /// Session deleted
    SessionDeleted { name: String },
    /// Snapshot taken
    SnapshotTaken,
    /// Error occurred
    Error { message: String },
}

// ---------------------------------------------------------------------------
// Session Manager Actor
// ---------------------------------------------------------------------------

/// Run the session manager actor loop.
/// Returns when shutdown flag is set or channel closes.
pub fn run_session_manager(
    bus: EventBus,
    mut channel: crate::event_bus::ActorChannel<BusEventEnvelope>,
    shutdown: Arc<AtomicBool>,
    snapshot_interval: Duration,
) {
    let mut state = SessionState::default();

    while !shutdown.load(Ordering::SeqCst) {
        // Check for commands (non-blocking)
        if let Ok(event) = channel.rx.try_recv() {
            match event {
                BusEventEnvelope::Domain(domain_event) => {
                    if let Err(e) = state.record_event(&domain_event) {
                        eprintln!("SessionManager: failed to record event: {}", e);
                    }
                }
                BusEventEnvelope::Ephemeral(_) => {
                    // Ephemeral events are not persisted
                }
            }
        }

        // Check if snapshot is needed
        if state.needs_snapshot(snapshot_interval) && state.has_active_session() {
            if let Err(e) = state.flush() {
                eprintln!("SessionManager: failed to snapshot: {}", e);
            } else {
                state.mark_snapshot();
            }
        }

        // Small sleep to avoid busy loop
        std::thread::sleep(Duration::from_millis(10));
    }

    // Cleanup on shutdown
    if let Err(e) = state.close_session() {
        eprintln!("SessionManager: failed to close session on shutdown: {}", e);
    }
}

// ---------------------------------------------------------------------------
// Convenience Functions
// ---------------------------------------------------------------------------

/// List all saved session names
pub fn list_sessions() -> anyhow::Result<Vec<String>> {
    session_jsonl::list_session_names()
}

/// Load a session by name, returning metadata and events
pub fn load_session(name: &str) -> anyhow::Result<(SessionMeta, Vec<DomainEvent>)> {
    session_jsonl::load_session(name)
}

/// Delete a session by name
pub fn delete_session(name: &str) -> anyhow::Result<()> {
    session_jsonl::delete_session(name)
}

/// Get the path for a session
pub fn session_path(name: &str) -> Option<PathBuf> {
    session_jsonl::session_path(name)
}

/// Start a new session and return the writer
pub fn start_session(
    name: &str,
    provider: &str,
    model: &str,
) -> anyhow::Result<(SessionMeta, JsonlWriter)> {
    let path = session_path(name)
        .ok_or_else(|| anyhow::anyhow!("No sessions directory"))?;

    // Ensure directory exists
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }

    let meta = SessionMeta::new(name.to_string(), provider.to_string(), model.to_string());
    let writer = JsonlWriter::create(&path, &meta)?;

    Ok((meta, writer))
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::{AtomicBool, Ordering};
    use std::sync::Arc;

    fn create_test_meta(name: &str) -> SessionMeta {
        SessionMeta::new(name.to_string(), "test".to_string(), "model".to_string())
    }

    fn tmp_session_path() -> (PathBuf, String) {
        let name = format!(
            "test_session_{}",
            std::process::id()
        );
        let path = std::env::temp_dir().join(format!("runie_test_{}.jsonl", name));
        let _ = std::fs::remove_file(&path);
        (path, name)
    }

    #[test]
    fn test_session_state_start_close() {
        let (path, name) = tmp_session_path();

        // Create temp dir
        let _ = std::fs::create_dir_all(path.parent().unwrap());

        let mut state = SessionState::default();
        assert!(!state.has_active_session());

        // Start session
        state.start_session(name.clone(), "test".to_string(), "model".to_string()).unwrap();
        assert!(state.has_active_session());
        assert!(state.is_dirty());

        // Record event
        let event = DomainEvent::Submit { content: "hello".to_string() };
        state.record_event(&event).unwrap();
        assert!(state.is_dirty());

        // Flush
        state.flush().unwrap();
        assert!(!state.is_dirty());

        // Close
        state.close_session().unwrap();
        assert!(!state.has_active_session());

        // Cleanup
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn test_session_state_record_events() {
        let (path, name) = tmp_session_path();
        let _ = std::fs::create_dir_all(path.parent().unwrap());

        let mut state = SessionState::default();
        state.start_session(name, "test".to_string(), "model".to_string()).unwrap();

        // Record multiple events
        let events = vec![
            DomainEvent::Submit { content: "first".to_string() },
            DomainEvent::SpawnAgent,
            DomainEvent::AgentThinking { id: "t1".to_string() },
        ];

        for event in &events {
            state.record_event(event).unwrap();
        }

        // Take pending events
        let pending = state.take_pending_events();
        assert_eq!(pending.len(), 3);

        // Should be empty now
        assert_eq!(state.take_pending_events().len(), 0);

        // Cleanup
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn test_session_state_snapshot_timing() {
        let mut state = SessionState::default();

        // No session = no snapshot needed
        assert!(state.needs_snapshot(Duration::from_secs(60)));

        // Start session
        state.start_session("test".to_string(), "test".to_string(), "model".to_string()).unwrap();
        assert!(state.needs_snapshot(Duration::from_secs(60)));

        // Mark snapshot taken
        state.mark_snapshot();

        // Immediate snapshot not needed (within interval)
        assert!(!state.needs_snapshot(Duration::from_secs(60)));
    }

    #[test]
    fn test_session_roundtrip_via_jsonl() {
        let (path, name) = tmp_session_path();
        let _ = std::fs::create_dir_all(path.parent().unwrap());

        let meta = create_test_meta(&name);

        // Write session
        {
            let mut writer = JsonlWriter::create(&path, &meta).unwrap();
            writer.write_event(&DomainEvent::Submit { content: "hello".to_string() }).unwrap();
            writer.write_event(&DomainEvent::SpawnAgent).unwrap();
            writer.flush().unwrap();
        }

        // Read session
        let (loaded_meta, events) = {
            let mut reader = JsonlReader::open(&path).unwrap();
            reader.read_session().unwrap()
        };

        assert_eq!(loaded_meta.name, name);
        assert_eq!(events.len(), 2);

        // Cleanup
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn test_list_sessions_empty() {
        // List from temp dir that doesn't exist
        let tmp_dir = std::env::temp_dir().join(format!("runie_empty_test_{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&tmp_dir);

        // Create empty sessions directory
        std::fs::create_dir_all(&tmp_dir).unwrap();

        // List should return empty
        let result = session_jsonl::list_session_names();
        // This will use default_sessions_dir, which may not be our temp dir
        // Just verify it doesn't panic
        assert!(result.is_ok() || result.is_err());

        // Cleanup
        let _ = std::fs::remove_dir_all(&tmp_dir);
    }

    #[test]
    fn test_delete_session() {
        let (path, name) = tmp_session_path();
        let _ = std::fs::create_dir_all(path.parent().unwrap());

        let meta = create_test_meta(&name);

        // Create session
        {
            let mut writer = JsonlWriter::create(&path, &meta).unwrap();
            writer.write_event(&DomainEvent::Submit { content: "test".to_string() }).unwrap();
            writer.flush().unwrap();
        }
        assert!(path.exists());

        // Delete via session_jsonl
        session_jsonl::delete_session(&name).unwrap();
        assert!(!path.exists());
    }

    #[test]
    fn test_session_state_resume() {
        let (path, name) = tmp_session_path();
        let _ = std::fs::create_dir_all(path.parent().unwrap());

        let meta = create_test_meta(&name);

        // Create session with events
        {
            let mut writer = JsonlWriter::create(&path, &meta).unwrap();
            writer.write_event(&DomainEvent::Submit { content: "original".to_string() }).unwrap();
            writer.flush().unwrap();
        }

        // Resume session
        let mut state = SessionState::default();
        state.resume_session(name.clone()).unwrap();
        assert!(state.has_active_session());

        // Record additional event
        state.record_event(&DomainEvent::AgentThinking { id: "t1".to_string() }).unwrap();

        // Read back and verify
        let (_meta, events) = {
            let mut reader = JsonlReader::open(&path).unwrap();
            reader.read_session().unwrap()
        };

        // Should have original + newly recorded
        assert_eq!(events.len(), 2);
        assert!(matches!(events[0], DomainEvent::Submit { .. }));
        assert!(matches!(events[1], DomainEvent::AgentThinking { .. }));

        // Cleanup
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn test_convenience_functions() {
        // Test session_path
        let path = session_path("my_session");
        assert!(path.is_some());
        assert!(path.unwrap().to_string_lossy().contains("my_session.jsonl"));
    }

    #[test]
    fn test_start_session_creates_directory() {
        let tmp_dir = std::env::temp_dir().join(format!(
            "runie_start_test_{}_{}",
            std::process::id(),
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let _ = std::fs::remove_dir_all(&tmp_dir);

        // Set up a temp sessions directory
        std::env::set_var("RUNIE_SESSIONS_DIR", tmp_dir.to_string_lossy().to_string());

        let result = start_session("new_session", "provider", "model");
        assert!(result.is_ok());

        // Verify file exists
        let session_file = tmp_dir.join("new_session.jsonl");
        assert!(session_file.exists());

        // Cleanup
        std::fs::remove_dir_all(&tmp_dir).ok();
        std::env::remove_var("RUNIE_SESSIONS_DIR");
    }
}

