#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct SessionMeta {
    pub version: u8,
    pub name: String,
    pub created_at: f64,
    pub updated_at: f64,
    pub provider: String,
    pub model: String,
}

impl SessionMeta {
    pub fn new(name: String, provider: String, model: String) -> Self {
        let now = timestamp();
        Self {
            version: 1,
            name,
            created_at: now,
            updated_at: now,
            provider,
            model,
        }
    }
}

const HEADER_TYPE: &str = "header";

pub struct JsonlWriter {
    writer: File,
}

impl JsonlWriter {
    pub fn create(path: &PathBuf, meta: &SessionMeta) -> std::io::Result<Self> {
        let file = File::create(path)?;
        let mut writer = Self { writer: file };
        writer.write_meta(meta)?;
        Ok(writer)
    }

    fn write_meta(&mut self, meta: &SessionMeta) -> std::io::Result<()> {
        let mut value = serde_json::to_value(meta).unwrap();
        if let Some(obj) = value.as_object_mut() {
            obj.insert("type".into(), serde_json::json!(HEADER_TYPE));
        }
        let json = serde_json::to_string(&value).unwrap();
        writeln!(self.writer, "{}", json)?;
        Ok(())
    }

    pub fn write_event(&mut self, event: &serde_json::Value) -> std::io::Result<()> {
        let json = serde_json::to_string(event).unwrap();
        writeln!(self.writer, "{}", json)?;
        Ok(())
    }

    pub fn flush(&mut self) -> std::io::Result<()> {
        self.writer.flush()?;
        Ok(())
    }
}

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub enum DomainEvent {
    Submit { content: String },
    SpawnAgent,
}

pub struct JsonlReader {
    reader: BufReader<File>,
    line_no: usize,
}

impl JsonlReader {
    pub fn open(path: &PathBuf) -> std::io::Result<Self> {
        let file = File::open(path)?;
        Ok(Self { reader: BufReader::new(file), line_no: 0 })
    }

    pub fn read_meta(&mut self) -> std::io::Result<SessionMeta> {
        let mut line = String::new();
        self.reader.read_line(&mut line)?;
        self.line_no = 1;
        line = line.trim_end().to_string();
        if line.is_empty() {
            panic!("empty session file");
        }
        let raw: serde_json::Value = serde_json::from_str(&line).unwrap();
        serde_json::from_value(raw).map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))
    }

    pub fn read_event(&mut self) -> std::io::Result<Option<DomainEvent>> {
        let mut line = String::new();
        match self.reader.read_line(&mut line)? as usize {
            0 => Ok(None),
            _ => {
                self.line_no += 1;
                let line = line.trim_end();
                if line.is_empty() {
                    return self.read_event();
                }
                let raw: serde_json::Value = serde_json::from_str(line).unwrap();
                let event: DomainEvent = serde_json::from_value(raw).unwrap();
                Ok(Some(event))
            }
        }
    }

    pub fn read_all_events(&mut self) -> std::io::Result<Vec<DomainEvent>> {
        let mut events = Vec::new();
        while let Some(evt) = self.read_event()? {
            events.push(evt);
        }
        Ok(events)
    }

    pub fn read_session(&mut self) -> std::io::Result<(SessionMeta, Vec<DomainEvent>)> {
        let meta = self.read_meta()?;
        let events = self.read_all_events()?;
        Ok((meta, events))
    }
}

